import { useState, useRef } from "react";

// ─── LOGO (large base64 asset — kept here to avoid separate asset import) ─────
const LOGO_SRC = "data:image/png;base64,";

import { WHITE, PAGE, SOFT, MID, HOT, PUNCH, DARK, BORDER } from './constants/colors.js';
import AuthScreen from './components/AuthScreen.jsx';
import HomeTab from './components/tabs/HomeTab.jsx';
import FlightsTab from './components/tabs/FlightsTab.jsx';
import StaysTab from './components/tabs/StaysTab.jsx';
import EatsTab from './components/tabs/EatsTab.jsx';
import PlanTab from './components/tabs/PlanTab.jsx';
import BudgetTab from './components/tabs/BudgetTab.jsx';
import MoodTab from './components/tabs/MoodTab.jsx';
import MOHTab from './components/tabs/MOHTab.jsx';
import DayOfTab from './components/tabs/DayOfTab.jsx';
import SplitTab from './components/tabs/SplitTab.jsx';
import ShopTab from './components/tabs/ShopTab.jsx';
import AlertsTab from './components/tabs/AlertsTab.jsx';
import DecorTab from './components/tabs/DecorTab.jsx';
import ProfileTab from './components/tabs/ProfileTab.jsx';
import PollsTab from './components/tabs/PollsTab.jsx';

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser]           = useState(null);
  const [tab, setTab]             = useState("home");
  const [groupSize, setGroupSize] = useState(8);
  const [cart, setCart]           = useState([]);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const alertCount                = 2;

  if (!user) return <AuthScreen onLogin={setUser} LOGO_SRC={LOGO_SRC} />;

  return (
    <div style={{ minHeight:"100vh", background:PAGE, color:DARK, maxWidth:430, margin:"0 auto", fontFamily:"'Playfair Display',Georgia,serif" }}>
      <div style={{ background:WHITE, borderBottom:`2px solid ${SOFT}`, position:"sticky", top:0, zIndex:100, boxShadow:`0 2px 12px rgba(230,101,130,0.08)` }}>
        <div style={{ padding:"10px 16px 8px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <img src={LOGO_SRC} alt="Bach Hotline" style={{ height:44, width:"auto", objectFit:"contain" }} />
          <div style={{ display:"flex", gap:8, alignItems:"center" }}>
            <div onClick={()=>setTab("alerts")} style={{ position:"relative", cursor:"pointer", fontSize:22 }}>
              🔔
              {alertCount>0&&<div style={{ position:"absolute", top:-4, right:-4, width:16, height:16, borderRadius:"50%", background:PUNCH, display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, fontWeight:800, fontFamily:"'DM Sans',sans-serif", color:WHITE, boxShadow:`0 2px 6px rgba(213,36,56,0.45)` }}>{alertCount}</div>}
            </div>
            <div onClick={()=>setTab("shop")} style={{ background:cart.length>0?`linear-gradient(135deg,${HOT},${PUNCH})`:SOFT, border:`1.5px solid ${cart.length>0?HOT:BORDER}`, borderRadius:50, padding:"6px 13px", fontSize:12, fontFamily:"'DM Sans',sans-serif", fontWeight:700, color:cart.length>0?WHITE:HOT, cursor:"pointer" }}>
              🛒 {cart.length}
            </div>
            <div onClick={()=>setTab("profile")} style={{ width:30, height:30, borderRadius:"50%", background:`linear-gradient(135deg,${HOT},${PUNCH})`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, cursor:"pointer", border:`2px solid ${WHITE}`, boxShadow:`0 2px 8px rgba(213,36,56,0.22)` }}>
              {user.avatar}
            </div>
          </div>
        </div>
        <div style={{ background:SOFT, padding:"5px 16px 6px", fontFamily:"'DM Sans',sans-serif", fontSize:10, color:HOT, fontWeight:600, letterSpacing:"0.5px", borderTop:`1px solid ${BORDER}` }}>
          Group of {groupSize} · {user.name.split(" ")[0]}
        </div>
      </div>
      <div style={{ padding:"16px 14px 120px", background:PAGE }}>
        {tab==="home"    && <HomeTab groupSize={groupSize} setGroupSize={setGroupSize} setTab={setTab} user={user} />}
        {tab==="flights" && <FlightsTab groupSize={groupSize} />}
        {tab==="stays"   && <StaysTab groupSize={groupSize} />}
        {tab==="eats"    && <EatsTab />}
        {tab==="plan"    && <PlanTab groupSize={groupSize} />}
        {tab==="budget"  && <BudgetTab groupSize={groupSize} />}
        {tab==="mood"    && <MoodTab />}
        {tab==="moh"     && <MOHTab groupSize={groupSize} />}
        {tab==="dayof"   && <DayOfTab />}
        {tab==="split"   && <SplitTab groupSize={groupSize} />}
        {tab==="shop"    && <ShopTab cart={cart} setCart={setCart} />}
        {tab==="alerts"  && <AlertsTab />}
        {tab==="decor"   && <DecorTab setTab={setTab} />}
        {tab==="profile" && <ProfileTab user={user} onLogout={()=>setUser(null)} cart={cart} />}
        {tab==="polls"   && <PollsTab user={user} />}
      </div>
      {/* ── BOTTOM NAV — 5 tabs + More drawer ── */}
      <div style={{ position:"fixed", bottom:0, left:"50%", transform:"translateX(-50%)", width:"100%", maxWidth:430, background:WHITE, borderTop:`1.5px solid ${SOFT}`, zIndex:200, boxShadow:`0 -2px 16px rgba(230,101,130,0.10)` }}>
        <div style={{ display:"flex" }}>
          {[
            { id:"home",  label:"Home" },
            { id:"plan",  label:"Plan" },
            { id:"polls", label:"Polls" },
            { id:"shop",  label:"Shop" },
            { id:"more",  label:"More" },
          ].map(n => {
            const isMore   = n.id === "more";
            const isActive = isMore ? drawerOpen : (tab === n.id && !drawerOpen);
            return (
              <button key={n.id}
                onClick={() => isMore ? setDrawerOpen(p => !p) : (setTab(n.id), setDrawerOpen(false))}
                style={{ flex:1, padding:"12px 4px 11px", background:"none", border:"none", cursor:"pointer",
                  display:"flex", flexDirection:"column", alignItems:"center", gap:2,
                  borderTop: isActive ? `2.5px solid ${HOT}` : "2.5px solid transparent",
                  color: isActive ? HOT : "#aaa",
                  transition:"color 0.18s",
                }}>
                <span style={{ fontSize:10, fontFamily:"'DM Sans',sans-serif", fontWeight:700, letterSpacing:"0.5px", textTransform:"uppercase" }}>{n.label}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* ── MORE DRAWER ── */}
      {drawerOpen && (
        <>
          <div onClick={() => setDrawerOpen(false)} style={{ position:"fixed", inset:0, background:"rgba(45,10,24,0.3)", zIndex:190, backdropFilter:"blur(3px)" }} />
          <div style={{ position:"fixed", bottom:0, left:"50%", transform:"translateX(-50%)", width:"100%", maxWidth:430, background:WHITE, borderRadius:"20px 20px 0 0", zIndex:195, boxShadow:`0 -4px 32px rgba(230,101,130,0.18)` }}>
            <div style={{ width:36, height:4, borderRadius:2, background:MID, margin:"14px auto 0" }} />
            <div style={{ padding:"16px 20px 32px" }}>
              <div style={{ fontSize:11, fontWeight:700, color:HOT, fontFamily:"'DM Sans',sans-serif", textTransform:"uppercase", letterSpacing:"1.5px", marginBottom:18 }}>All Features</div>
              <div style={{ fontSize:10, color:"#bbb", fontFamily:"'DM Sans',sans-serif", textTransform:"uppercase", letterSpacing:"1px", marginBottom:10, fontWeight:600 }}>Trip Planning</div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:20 }}>
                {[
                  { id:"flights", label:"Flights",   sub:"Search & compare"        },
                  { id:"stays",   label:"Stays",     sub:"Airbnb, Vrbo & hotels"   },
                  { id:"eats",    label:"Eats",      sub:"Restaurants & activities" },
                  { id:"budget",  label:"Budget",    sub:"Estimate trip cost"       },
                  { id:"split",   label:"Split",     sub:"Divide expenses"          },
                  { id:"dayof",   label:"Day-Of",    sub:"Live itinerary mode"      },
                  { id:"polls",   label:"Polls",     sub:"Group voting"             },
                ].map(item => (
                  <button key={item.id} onClick={() => { setTab(item.id); setDrawerOpen(false); }}
                    style={{ background: tab===item.id ? SOFT : PAGE, border:`1.5px solid ${tab===item.id ? HOT : BORDER}`, borderRadius:14, padding:"12px 13px", cursor:"pointer", textAlign:"left", transition:"all 0.15s" }}>
                    <div style={{ fontSize:13, fontWeight:700, fontFamily:"'Playfair Display',Georgia,serif", color: tab===item.id ? HOT : DARK }}>{item.label}</div>
                    <div style={{ fontSize:11, color:"#aaa", fontFamily:"'DM Sans',sans-serif", marginTop:2, lineHeight:1.3 }}>{item.sub}</div>
                  </button>
                ))}
              </div>
              <div style={{ fontSize:10, color:"#bbb", fontFamily:"'DM Sans',sans-serif", textTransform:"uppercase", letterSpacing:"1px", marginBottom:10, fontWeight:600 }}>Extras</div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
                {[
                  { id:"mood",    label:"Vibes",      sub:"Theme & mood board"   },
                  { id:"decor",   label:"AI Décor",   sub:"Visualize your space"  },
                  { id:"alerts",  label:"Alerts",     sub:"Price drop alerts"     },
                  { id:"profile", label:"Profile",    sub:"Settings & trips"      },
                ].map(item => (
                  <button key={item.id} onClick={() => { setTab(item.id); setDrawerOpen(false); }}
                    style={{ background: tab===item.id ? SOFT : PAGE, border:`1.5px solid ${tab===item.id ? HOT : BORDER}`, borderRadius:14, padding:"12px 13px", cursor:"pointer", textAlign:"left", transition:"all 0.15s" }}>
                    <div style={{ fontSize:13, fontWeight:700, fontFamily:"'Playfair Display',Georgia,serif", color: tab===item.id ? HOT : DARK }}>{item.label}</div>
                    <div style={{ fontSize:11, color:"#aaa", fontFamily:"'DM Sans',sans-serif", marginTop:2, lineHeight:1.3 }}>{item.sub}</div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
